      "content": "// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/cryptography/Hashes.sol";

import "./access/AccessControl.sol";
import "./access/PauserControl.sol";

contract RewardsClaim is AccessControl, PauserControl {
    using SafeERC20 for IERC20;

    // e844ed9e40aeb388cb97d2ef796e81de635718f440751efb46753791698f6bde
    bytes32 public constant ROOT_UPDATER_ROLE = keccak256("root_updater");
    // Role allowed to update the reward token address
    // 18ec319775fc93713626304e22a3fa004f973e131b63028717db682979b642d8
    bytes32 public constant REWARD_TOKEN_SETTER_ROLE = keccak256("reward_token_setter");

    address public rewardToken;

    uint256 public coolDownPeriod = 1 hours; // Cooldown period for claiming rewards

    struct ClaimInfo {
        uint256 claimedAmount; // Cumulative amount of rewards claimed
        uint256 lastClaimedTime; // Last time the user claimed rewards
    }

    mapping(address => ClaimInfo) public userClaimed;

    uint256 public totalClaimed;

    uint64 public epoch;
    bytes32 public topRoot;

    event TopRootUpdated(uint64 indexed epoch, bytes32 topRoot);
    event UserRewardsClaimed(address indexed user, uint256 newAmount, uint256 cumulativeAmounts);
    event IncentivesSwept(address to, uint256 amount);
    event CoolDownPeriodUpdated(uint256 newCoolDownPeriod);
    event RewardTokenUpdated(address newRewardToken);

    function init(address owner, address rootUpdater, address pauser, address rewardTokenSetter, address _rewardToken, uint256 _coolDownPeriod)
        external
    {
        initOwner(owner);
        _grantRole(ROOT_UPDATER_ROLE, rootUpdater);
        _grantRole(PAUSER_ROLE, pauser);
        _grantRole(REWARD_TOKEN_SETTER_ROLE, rewardTokenSetter);
        rewardToken = _rewardToken;
        if (_coolDownPeriod > 0) {
            coolDownPeriod = _coolDownPeriod;
        }
    }

    /**
     * @notice Updates the reward token address.
     * @dev Restricted to REWARD_TOKEN_SETTER_ROLE. Owner can grant/revoke this role.
     * @param _rewardToken New ERC20 token address used for rewards.
     */
    function setRewardToken(address _rewardToken) external onlyRole(REWARD_TOKEN_SETTER_ROLE) {
        require(_rewardToken != address(0), "invalid token");
        rewardToken = _rewardToken;
        emit RewardTokenUpdated(_rewardToken);
    }

    /**
     * @notice Updates the epoch and top Merkle root info
     * @param _epoch The epoch number.
     * @param _topRoot The Merkle root for the top tree.
     */
    function updateRoot(uint64 _epoch, bytes32 _topRoot) external onlyRole(ROOT_UPDATER_ROLE) whenNotPaused {
        epoch = _epoch;
        topRoot = _topRoot;
        emit TopRootUpdated(epoch, topRoot);
    }

    /**
     * @notice Claims rewards for a user using a combined sub tree + top tree Merkle proof.
     * @param user The user address.
     * @param cumulativeAmount The cumulative reward amount.
     * @param _epoch The epoch of the proof
     * @param proof The Merkle proof from the sub tree leaf node to the top tree root.
     */
    function claim(address user, uint256 cumulativeAmount, uint64 _epoch, bytes32[] calldata proof) external {
        require(_epoch == epoch, "invalid epoch");
        require(userClaimed[user].lastClaimedTime + coolDownPeriod <= block.timestamp, "cooldown period not met");
        require(cumulativeAmount > userClaimed[user].claimedAmount, "no new rewards to claim");
        bytes32 leafHash = keccak256(abi.encodePacked(user, cumulativeAmount));
        require(verifyMerkleProof(proof, topRoot, leafHash), "verification failed");
        uint256 newAmount = cumulativeAmount - userClaimed[user].claimedAmount;
        userClaimed[user].claimedAmount += newAmount;
        userClaimed[user].lastClaimedTime = block.timestamp;
        totalClaimed += newAmount;
        // Send reward token
        IERC20(rewardToken).safeTransfer(user, newAmount);
        emit UserRewardsClaimed(user, newAmount, cumulativeAmount);
    }

    function verifyMerkleProof(bytes32[] memory proof, bytes32 root, bytes32 leafHash) private pure returns (bool) {
        bytes32 hash = leafHash;
        for (uint256 i = 0; i < proof.length; i++) {
            hash = Hashes.commutativeKeccak256(hash, proof[i]);
        }
        return hash == root;
    }

    function sweepIncentives(address to, uint256 amount) external onlyOwner whenPaused {
        require(amount > 0, "amount must be greater than 0");
        IERC20(rewardToken).safeTransfer(to, amount);
        emit IncentivesSwept(to, amount);
    }

    function setCoolDownPeriod(uint256 _coolDownPeriod) external onlyOwner {
        coolDownPeriod = _coolDownPeriod;
        emit CoolDownPeriodUpdated(_coolDownPeriod);
    }
}
"
